'use strict';

// MODULES //

import numelDimension from '@stdlib/ndarray-base-numel-dimension';
import getStride from '@stdlib/ndarray-base-stride';
import getOffset from '@stdlib/ndarray-base-offset';
import getData from '@stdlib/ndarray-base-data-buffer';
import { ndarray as strided } from '@stdlib/blas-ext-base-dfill-not-equal';
import ndarraylike2scalar from '@stdlib/ndarray-base-ndarraylike2scalar';


// MAIN //

/**
* Replaces elements in a one-dimensional double-precision floating-point ndarray not equal to a provided search element with a specified scalar constant.
*
* ## Notes
*
* -   The function expects the following ndarrays:
*
*     -   a one-dimensional input ndarray.
*     -   a zero-dimensional ndarray containing the search element.
*     -   a zero-dimensional ndarray containing the scalar constant.
*
* -   When comparing elements, the function checks for equality using the strict equality operator `===`. As a consequence, `NaN` values are considered distinct (i.e., as `NaN !== NaN` always evaluates to `true`, `NaN` elements are always replaced), and `-0` and `+0` are considered the same.
*
* @param {ArrayLikeObject<Object>} arrays - array-like object containing ndarrays
* @returns {ndarray} input ndarray
*
* @example
* import Float64Vector from '@stdlib/ndarray-vector-float64';
* import scalar2ndarray from '@stdlib/ndarray-from-scalar';
*
* var x = new Float64Vector( [ 0.0, -2.0, 3.0, 0.0, 4.0, -6.0 ] );
*
* var searchElement = scalar2ndarray( 0.0, {
*     'dtype': 'float64'
* });
*
* var alpha = scalar2ndarray( 5.0, {
*     'dtype': 'float64'
* });
*
* var out = dfillNotEqual( [ x, searchElement, alpha ] );
* // returns <ndarray>[ 0.0, 5.0, 5.0, 0.0, 5.0, 5.0 ]
*/
function dfillNotEqual( arrays ) {
	var searchElement;
	var alpha;
	var x;

	x = arrays[ 0 ];
	searchElement = ndarraylike2scalar( arrays[ 1 ] );
	alpha = ndarraylike2scalar( arrays[ 2 ] );
	strided( numelDimension( x, 0 ), searchElement, alpha, getData( x ), getStride( x, 0 ), getOffset( x ) ); // eslint-disable-line max-len
	return x;
}


// EXPORTS //

export default dfillNotEqual;
