'use strict';

// MODULES //

import numelDimension from '@stdlib/ndarray-base-numel-dimension';
import getStride from '@stdlib/ndarray-base-stride';
import getOffset from '@stdlib/ndarray-base-offset';
import getData from '@stdlib/ndarray-base-data-buffer';
import { ndarray as strided } from '@stdlib/blas-ext-base-gindex-of-falsy';


// MAIN //

/**
* Returns the index of the first falsy element in a one-dimensional ndarray.
*
* ## Notes
*
* -   The function expects the following ndarrays:
*
*     -   a one-dimensional input ndarray.
*
* @param {ArrayLikeObject<Object>} arrays - array-like object containing ndarrays
* @returns {integer} index
*
* @example
* import vector from '@stdlib/ndarray-vector-ctor';
*
* var x = vector( [ 1.0, 3.0, 0.0, 2.0 ], 'generic' );
*
* var v = gindexOfFalsy( [ x ] );
* // returns 2
*/
function gindexOfFalsy( arrays ) {
	var x = arrays[ 0 ];
	return strided( numelDimension( x, 0 ), getData( x ), getStride( x, 0 ), getOffset( x ) ); // eslint-disable-line max-len
}


// EXPORTS //

export default gindexOfFalsy;
