'use strict';

/**
* Return the index of the first falsy element in a double-precision floating-point strided array.
*
* @module @stdlib/blas-ext-base-dindex-of-falsy
*
* @example
* import Float64Array from '@stdlib/array-float64';
* import dindexOfFalsy from '@stdlib/blas-ext-base-dindex-of-falsy';
*
* var x = new Float64Array( [ 3.0, 3.0, 0.0, 3.0, 4.0, 3.0, -1.0, 3.0 ] );
*
* var idx = dindexOfFalsy( x.length, x, 1 );
* // returns 2
*
* @example
* import Float64Array from '@stdlib/array-float64';
* import dindexOfFalsy from '@stdlib/blas-ext-base-dindex-of-falsy';
*
* var x = new Float64Array( [ 3.0, 3.0, 0.0, 3.0, 4.0, 3.0, -1.0, 3.0 ] );
*
* var idx = dindexOfFalsy.ndarray( x.length, x, 1, 0 );
* // returns 2
*/

// MODULES //

var join = require( 'path' ).join;
import tryRequire from '@stdlib/utils-try-require';
import isError from '@stdlib/assert-is-error';
import main from './main.js';


// MAIN //

var dindexOfFalsy;
var tmp = tryRequire( join( __dirname, './native.js' ) );
if ( isError( tmp ) ) {
	dindexOfFalsy = main;
} else {
	dindexOfFalsy = tmp;
}


// EXPORTS //

export default dindexOfFalsy;

// exports: { "ndarray": "dindexOfFalsy.ndarray" }
